"""Unit tests for LoanService."""import pytestfrom datetime import datetime, timedeltafrom src.models.book import Bookfrom src.models.member import Memberfrom src.models.loan import LoanRecordfrom src.collections.book_collection import BookCollectionfrom src.collections.member_collection import MemberCollectionfrom src.collections.loan_collection import LoanCollectionfrom src.services.loan_service import LoanServiceclass TestLoanService:    """Test suite for LoanService."""    @pytest.fixture    def setup_service(self):        books = BookCollection()        members = MemberCollection()        loans = LoanCollection()        # Add test data        book = Book("Test Book", "Author", "123", 2024)        books.add_book(book)        member = Member("Test Member", "M001", "test@test.com")        members.add_member(member)        service = LoanService(books, members, loans)        return service, books, members, loans    def test_check_out_book_success(self, setup_service):        service, books, members, loans = setup_service        success, msg, loan = service.check_out_book("M001", "123")        assert success is True        assert "checked out" in msg        assert loan is not None        assert loans.count_active() == 1        assert not books.find_by_isbn("123").is_available()        assert members.find_by_id("M001").get_borrowed_count() == 1    def test_check_out_book_not_found(self, setup_service):        service, _, _, _ = setup_service        success, msg, loan = service.check_out_book("M001", "999")        assert success is False        assert "not found" in msg    def test_check_out_member_not_found(self, setup_service):        service, _, _, _ = setup_service        success, msg, loan = service.check_out_book("M999", "123")        assert success is False        assert "Member" in msg    def test_check_out_book_already_checked_out(self, setup_service):        service, books, _, _ = setup_service        service.check_out_book("M001", "123")        success, msg, _ = service.check_out_book("M001", "123")        assert success is False        assert "already checked out" in msg    def test_check_in_book_success_no_fine(self, setup_service):        service, books, members, loans = setup_service        # Check out        service.check_out_book("M001", "123")        # Return on time        success, msg, fine = service.check_in_book("123")        assert success is True        assert "No fine" in msg        assert fine == 0.0        assert books.find_by_isbn("123").is_available()        assert members.find_by_id("M001").get_borrowed_count() == 0    def test_check_in_book_with_fine(self, setup_service):        service, books, members, loans = setup_service        # Check out and manually make overdue        success, _, loan = service.check_out_book("M001", "123")        loan.due_date = datetime.now() - timedelta(days=5)        success, msg, fine = service.check_in_book("123")        assert success is True        assert fine > 0        assert members.find_by_id("M001").get_fines_owed() == fine